use std::fmt::Write as _;
use std::path::PathBuf;

use anyhow::Context;
use clap::Parser;
use locus_schema::{Cardinality, GraphSchema, NodeSelector};

#[derive(Debug, Parser)]
#[command(name = "locus-codegen")]
#[command(about = "Generate TypeScript helpers from a Locus schema")]
struct Args {
    #[arg(long, default_value = "schema.yaml")]
    schema: PathBuf,
    #[arg(long)]
    out: Option<PathBuf>,
}

fn main() -> anyhow::Result<()> {
    let args = Args::parse();
    let schema = GraphSchema::load(&args.schema)
        .with_context(|| format!("load schema {}", args.schema.display()))?;
    let output = generate_typescript(&schema);

    if let Some(out) = args.out {
        std::fs::write(&out, output).with_context(|| format!("write {}", out.display()))?;
    } else {
        print!("{output}");
    }

    Ok(())
}

fn generate_typescript(schema: &GraphSchema) -> String {
    let mut out = String::new();
    writeln!(
        out,
        "/* eslint-disable */\n// Generated by locus-codegen. Do not edit by hand.\n\nimport Gio from 'gi://Gio?version=2.0';\nimport GLib from 'gi://GLib?version=2.0';\n"
    )
    .unwrap();

    write_string_union(
        &mut out,
        "NodeKind",
        schema.nodes().keys().map(String::as_str),
    );
    write_string_union(
        &mut out,
        "Relation",
        schema.relations().keys().map(String::as_str),
    );
    write_string_union(
        &mut out,
        "NamedPath",
        schema.paths().keys().map(String::as_str),
    );

    writeln!(
        out,
        "export type NodeId = string;\nexport type OptionalNodeId = NodeId | null;\nexport type Unsubscribe = () => void;\n"
    )
    .unwrap();

    writeln!(
        out,
        "export type NodeSelector =\n  | {{ type: \"any\" }}\n  | {{ type: \"kind\"; kind: NodeKind | string }}\n  | {{ type: \"exact\"; id: NodeId }};\n"
    )
    .unwrap();

    writeln!(out, "export const locusSchema = {{").unwrap();
    write_nodes(&mut out, schema);
    write_relations(&mut out, schema);
    write_paths(&mut out, schema);
    writeln!(out, "}} as const;\n").unwrap();

    write_property_types(&mut out, schema);
    write_dbus_client(&mut out);
    out
}

fn write_string_union<'a>(out: &mut String, name: &str, values: impl Iterator<Item = &'a str>) {
    let values = values.collect::<Vec<_>>();
    if values.is_empty() {
        writeln!(out, "export type {name} = never;\n").unwrap();
        return;
    }

    writeln!(out, "export type {name} =").unwrap();
    for value in values {
        writeln!(out, "  | {value:?}").unwrap();
    }
    writeln!(out, ";\n").unwrap();
}

fn write_nodes(out: &mut String, schema: &GraphSchema) {
    writeln!(out, "  nodes: {{").unwrap();
    for (kind, node) in schema.nodes() {
        writeln!(out, "    {kind:?}: {{").unwrap();
        writeln!(out, "      properties: {{").unwrap();
        for (property, spec) in &node.properties {
            writeln!(
                out,
                "        {property:?}: {{ required: {required} }},",
                required = spec.required
            )
            .unwrap();
        }
        writeln!(out, "      }},").unwrap();
        writeln!(out, "    }},").unwrap();
    }
    writeln!(out, "  }},").unwrap();
}

fn write_relations(out: &mut String, schema: &GraphSchema) {
    writeln!(out, "  relations: {{").unwrap();
    for (name, relation) in schema.relations() {
        writeln!(out, "    {name:?}: {{").unwrap();
        writeln!(out, "      from: {},", selector_ts(&relation.source)).unwrap();
        writeln!(out, "      to: {},", selector_ts(&relation.target)).unwrap();
        writeln!(
            out,
            "      cardinality: {cardinality:?},",
            cardinality =
                cardinality_name(relation.sources_per_target, relation.targets_per_source)
        )
        .unwrap();
        writeln!(out, "    }},").unwrap();
    }
    writeln!(out, "  }},").unwrap();
}

fn write_paths(out: &mut String, schema: &GraphSchema) {
    writeln!(out, "  paths: {{").unwrap();
    for (name, path) in schema.paths() {
        writeln!(out, "    {name:?}: {{").unwrap();
        writeln!(out, "      from: {:?},", path.source).unwrap();
        write!(out, "      path: [").unwrap();
        for (index, relation) in path.path.iter().enumerate() {
            if index > 0 {
                write!(out, ", ").unwrap();
            }
            write!(out, "{relation:?}").unwrap();
        }
        writeln!(out, "],").unwrap();
        writeln!(out, "    }},").unwrap();
    }
    writeln!(out, "  }},").unwrap();
}

fn write_property_types(out: &mut String, schema: &GraphSchema) {
    writeln!(out, "export type PropertyKeyByKind = {{").unwrap();
    for (kind, node) in schema.nodes() {
        write!(out, "  {kind:?}: ").unwrap();
        if node.properties.is_empty() {
            writeln!(out, "never;").unwrap();
        } else {
            let mut first = true;
            for property in node.properties.keys() {
                if !first {
                    write!(out, " | ").unwrap();
                }
                first = false;
                write!(out, "{property:?}").unwrap();
            }
            writeln!(out, ";").unwrap();
        }
    }
    writeln!(out, "}};\n").unwrap();
    writeln!(
        out,
        "export type PropertyKey = PropertyKeyByKind[NodeKind];\n"
    )
    .unwrap();
}

fn write_dbus_client(out: &mut String) {
    writeln!(
        out,
        "export type LocusClientOptions = {{\n  traceLatency?: boolean;\n}};\n\nexport type LinkAddedSignal = {{ type: 'link-added'; source: NodeId; relation: Relation; target: NodeId }};\nexport type LinkRemovedSignal = {{ type: 'link-removed'; source: NodeId; relation: Relation; target: NodeId }};\nexport type LinkSetSignal = {{ type: 'link-set'; source: NodeId; relation: Relation; oldTargets: NodeId[]; target: NodeId }};\nexport type PropertyChangedSignal = {{ type: 'property-changed'; subject: NodeId; key: PropertyKey; value: string }};\nexport type PropertyRemovedSignal = {{ type: 'property-removed'; subject: NodeId; key: PropertyKey }};\nexport type ResolveChangedSignal = {{ type: 'resolve-changed'; source: NodeId; path: Relation[]; target: OptionalNodeId }};\n\nconst BUS_NAME = 'io.github.Locus';\nconst ROOT_PATH = '/io/github/Locus';\nconst GRAPH_IFACE = 'io.github.Locus.Graph';\nconst WATCH_IFACE = 'io.github.Locus.Watch';\nconst PROPERTIES_IFACE = 'org.freedesktop.DBus.Properties';\nconst NONE = '';\n\nfunction none(value: string): OptionalNodeId {{\n  return value.length === 0 ? null : value;\n}}\n\nfunction unpackVariant(value: any): any {{\n  return value && typeof value.deepUnpack === 'function' ? value.deepUnpack() : value;\n}}\n\nexport function samePath(left: readonly string[], right: readonly string[]): boolean {{\n  return left.length === right.length && left.every((part, index) => part === right[index]);\n}}\n\nexport function path(name: NamedPath): {{ from: NodeId; path: Relation[] }} {{\n  const spec = locusSchema.paths[name];\n  return {{ from: spec.from, path: [...spec.path] }};\n}}\n\nfunction nowMs(): number {{\n  return GLib.get_monotonic_time() / 1000;\n}}\n\nexport class LocusWatch {{\n  constructor(private readonly client: LocusDbusClient, readonly objectPath: string) {{}}\n\n  async source(): Promise<NodeId> {{\n    return await this.client.watchProperty(this.objectPath, 'Source') as NodeId;\n  }}\n\n  async path(): Promise<Relation[]> {{\n    return await this.client.watchProperty(this.objectPath, 'Path') as Relation[];\n  }}\n\n  async target(): Promise<OptionalNodeId> {{\n    return none(await this.client.watchProperty(this.objectPath, 'Target') as string);\n  }}\n\n  onTargetChanged(handler: (target: OptionalNodeId) => void): Unsubscribe {{\n    return this.client.onWatchPropertiesChanged(this.objectPath, changed => {{\n      if (!Object.prototype.hasOwnProperty.call(changed, 'Target')) return;\n      handler(none(String(unpackVariant(changed.Target) ?? '')));\n    }});\n  }}\n\n  close(): Promise<void> {{\n    return this.client.closeWatch(this.objectPath);\n  }}\n}}\n\nexport class LocusDbusClient {{\n  private readonly traceLatency: boolean;\n\n  constructor(options: LocusClientOptions = {{}}) {{\n    this.traceLatency = options.traceLatency ?? false;\n  }}\n\n  setLink(source: NodeId, relation: Relation, target: NodeId): Promise<void> {{\n    return this.callGraph('SetLink', new GLib.Variant('(sss)', [source, relation, target]), null, () => undefined);\n  }}\n\n  removeLink(source: NodeId, relation: Relation, target: NodeId): Promise<void> {{\n    return this.callGraph('RemoveLink', new GLib.Variant('(sss)', [source, relation, target]), null, () => undefined);\n  }}\n\n  removeLinks(source: NodeId, relation: Relation): Promise<void> {{\n    return this.callGraph('RemoveLinks', new GLib.Variant('(ss)', [source, relation]), null, () => undefined);\n  }}\n\n  targets(source: NodeId, relation: Relation): Promise<NodeId[]> {{\n    return this.callGraph('GetTargets', new GLib.Variant('(ss)', [source, relation]), '(as)', ([targets]) => targets as NodeId[]);\n  }}\n\n  sources(target: NodeId, relation: Relation): Promise<NodeId[]> {{\n    return this.callGraph('GetSources', new GLib.Variant('(ss)', [target, relation]), '(as)', ([sources]) => sources as NodeId[]);\n  }}\n\n  setProperty(subject: NodeId, key: PropertyKey, value: string): Promise<void> {{\n    return this.callGraph('SetProperty', new GLib.Variant('(sss)', [subject, key, value]), null, () => undefined);\n  }}\n\n  async property(subject: NodeId, key: PropertyKey): Promise<OptionalNodeId> {{\n    return none(await this.callGraph('GetProperty', new GLib.Variant('(ss)', [subject, key]), '(s)', ([value]) => value as string));\n  }}\n\n  properties(subject: NodeId): Promise<Record<string, string>> {{\n    return this.callGraph('GetProperties', new GLib.Variant('(s)', [subject]), '(a{{ss}})', ([properties]) => properties as Record<string, string>);\n  }}\n\n  async resolve(source: NodeId, relations: Relation[]): Promise<OptionalNodeId> {{\n    return none(await this.callGraph('Resolve', new GLib.Variant('(sas)', [source, relations]), '(s)', ([target]) => target as string));\n  }}\n\n  resolveAll(source: NodeId, relations: Relation[]): Promise<NodeId[]> {{\n    return this.callGraph('ResolveAll', new GLib.Variant('(sas)', [source, relations]), '(as)', ([targets]) => targets as NodeId[]);\n  }}\n\n  resolvePath(name: NamedPath): Promise<OptionalNodeId> {{\n    const spec = path(name);\n    return this.resolve(spec.from, spec.path);\n  }}\n\n  resolveAllPath(name: NamedPath): Promise<NodeId[]> {{\n    const spec = path(name);\n    return this.resolveAll(spec.from, spec.path);\n  }}\n\n  async subscribeResolve(source: NodeId, relations: Relation[]): Promise<OptionalNodeId> {{\n    return none(await this.callGraph('SubscribeResolve', new GLib.Variant('(sas)', [source, relations]), '(s)', ([target]) => target as string));\n  }}\n\n  subscribePath(name: NamedPath): Promise<OptionalNodeId> {{\n    const spec = path(name);\n    return this.subscribeResolve(spec.from, spec.path);\n  }}\n\n  async watchNode(source: NodeId, relations: Relation[]): Promise<LocusWatch> {{\n    const objectPath = await this.callGraph('WatchNode', new GLib.Variant('(sas)', [source, relations]), '(o)', ([objectPath]) => objectPath as string);\n    return new LocusWatch(this, objectPath);\n  }}\n\n  watchPath(name: NamedPath): Promise<LocusWatch> {{\n    const spec = path(name);\n    return this.watchNode(spec.from, spec.path);\n  }}\n\n  onLinkAdded(handler: (signal: LinkAddedSignal) => void): Unsubscribe {{\n    return this.subscribeSignal(GRAPH_IFACE, 'LinkAdded', null, null, params => {{\n      const [source, relation, target] = params.deepUnpack() as [NodeId, Relation, NodeId];\n      handler({{ type: 'link-added', source, relation, target }});\n    }});\n  }}\n\n  onLinkRemoved(handler: (signal: LinkRemovedSignal) => void): Unsubscribe {{\n    return this.subscribeSignal(GRAPH_IFACE, 'LinkRemoved', null, null, params => {{\n      const [source, relation, target] = params.deepUnpack() as [NodeId, Relation, NodeId];\n      handler({{ type: 'link-removed', source, relation, target }});\n    }});\n  }}\n\n  onLinkSet(handler: (signal: LinkSetSignal) => void): Unsubscribe {{\n    return this.subscribeSignal(GRAPH_IFACE, 'LinkSet', null, null, params => {{\n      const [source, relation, oldTargets, target] = params.deepUnpack() as [NodeId, Relation, NodeId[], NodeId];\n      handler({{ type: 'link-set', source, relation, oldTargets, target }});\n    }});\n  }}\n\n  onPropertyChanged(handler: (signal: PropertyChangedSignal) => void): Unsubscribe {{\n    return this.subscribeSignal(GRAPH_IFACE, 'PropertyChanged', null, null, params => {{\n      const [subject, key, value] = params.deepUnpack() as [NodeId, PropertyKey, string];\n      handler({{ type: 'property-changed', subject, key, value }});\n    }});\n  }}\n\n  onPropertyRemoved(handler: (signal: PropertyRemovedSignal) => void): Unsubscribe {{\n    return this.subscribeSignal(GRAPH_IFACE, 'PropertyRemoved', null, null, params => {{\n      const [subject, key] = params.deepUnpack() as [NodeId, PropertyKey];\n      handler({{ type: 'property-removed', subject, key }});\n    }});\n  }}\n\n  onResolveChanged(handler: (signal: ResolveChangedSignal) => void, source?: NodeId): Unsubscribe {{\n    return this.subscribeSignal(GRAPH_IFACE, 'ResolveChanged', null, source ?? null, params => {{\n      const [changedSource, changedPath, target] = params.deepUnpack() as [NodeId, Relation[], string];\n      handler({{ type: 'resolve-changed', source: changedSource, path: changedPath, target: none(target) }});\n    }});\n  }}\n\n  watchProperty(objectPath: string, property: 'Source' | 'Path' | 'Target'): Promise<string | string[]> {{\n    return this.callOn(objectPath, PROPERTIES_IFACE, 'Get', new GLib.Variant('(ss)', [WATCH_IFACE, property]), '(v)', ([value]) => unpackVariant(value));\n  }}\n\n  onWatchPropertiesChanged(objectPath: string, handler: (changed: Record<string, any>) => void): Unsubscribe {{\n    return this.subscribeSignal(PROPERTIES_IFACE, 'PropertiesChanged', objectPath, WATCH_IFACE, params => {{\n      const [iface, changed] = params.deepUnpack() as [string, Record<string, any>, string[]];\n      if (iface === WATCH_IFACE) handler(changed);\n    }});\n  }}\n\n  closeWatch(objectPath: string): Promise<void> {{\n    return this.callOn(objectPath, WATCH_IFACE, 'Close', null, null, () => undefined);\n  }}\n\n  private callGraph<T>(method: string, params: GLib.Variant | null, resultType: string | null, unpack: (result: any) => T): Promise<T> {{\n    return this.callOn(ROOT_PATH, GRAPH_IFACE, method, params, resultType, unpack);\n  }}\n\n  private callOn<T>(objectPath: string, iface: string, method: string, params: GLib.Variant | null, resultType: string | null, unpack: (result: any) => T): Promise<T> {{\n    return new Promise((resolve, reject) => {{\n      const start = nowMs();\n      Gio.DBus.session.call(\n        BUS_NAME,\n        objectPath,\n        iface,\n        method,\n        params,\n        resultType ? new GLib.VariantType(resultType) : null,\n        Gio.DBusCallFlags.NONE,\n        -1,\n        null,\n        (_conn: any, res: any) => {{\n          try {{\n            const result = Gio.DBus.session.call_finish(res);\n            const value = unpack(result.deepUnpack());\n            this.logLatency(`${{iface}}.${{method}}`, start);\n            resolve(value);\n          }} catch (error) {{\n            this.logLatency(`${{iface}}.${{method}}`, start, true);\n            reject(error);\n          }}\n        }},\n      );\n    }});\n  }}\n\n  private subscribeSignal(iface: string, signal: string, objectPath: string | null, arg0: string | null, handler: (params: GLib.Variant) => void): Unsubscribe {{\n    const id = Gio.DBus.session.signal_subscribe(\n      BUS_NAME,\n      iface,\n      signal,\n      objectPath,\n      arg0,\n      Gio.DBusSignalFlags.NONE,\n      (_conn: any, _sender: any, _path: any, _iface: any, _signal: string, params: GLib.Variant) => handler(params),\n    );\n    return () => Gio.DBus.session.signal_unsubscribe(id);\n  }}\n\n  private logLatency(method: string, start: number, failed = false): void {{\n    if (!this.traceLatency) return;\n    const elapsed = (nowMs() - start).toFixed(1);\n    const status = failed ? ' failed' : '';\n    console.log(`[LocusDbus] ${{method}}${{status}} +${{elapsed}}ms`);\n  }}\n}}\n"
    )
    .unwrap();
}

fn selector_ts(selector: &NodeSelector) -> String {
    match selector {
        NodeSelector::Any => "{ type: \"any\" }".to_string(),
        NodeSelector::Kind(kind) => format!("{{ type: \"kind\", kind: {kind:?} }}"),
        NodeSelector::Exact(id) => format!("{{ type: \"exact\", id: {id:?} }}"),
    }
}

fn cardinality_name(
    sources_per_target: Cardinality,
    targets_per_source: Cardinality,
) -> &'static str {
    match (sources_per_target, targets_per_source) {
        (Cardinality::One, Cardinality::One) => "one-to-one",
        (Cardinality::Many, Cardinality::One) => "many-to-one",
        (Cardinality::One, Cardinality::Many) => "one-to-many",
        (Cardinality::Many, Cardinality::Many) => "many-to-many",
    }
}
